import { Component, ViewChild } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { ApiService } from '@services/api.service';
import { tap, delay, merge, startWith, switchMap, map } from 'rxjs';

@Component({
  selector: 'app-memberships-list',
  templateUrl: './memberships-list.component.html',
  styleUrls: ['./memberships-list.component.scss']
})
export class MembershipsListComponent {
  query: string = "";
  isLoadingResults = true;

  displayedColumns: string[] = ['membership_id', 'user_name', 'membership_plan', 'membership_charge', 'duration', 'expiredAt'];
  data : any[] = [];
  resultsLength = 0;
  sortBy: string = 'membership_id'
  

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;


  constructor(private api: ApiService, private fb: FormBuilder) {

  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.listActiveMemberships(this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.memberships
          
        }),
      )
      .subscribe(data => this.data = data);

  }
}
